        arb_short_text().prop_map(search_input::Event::Change),
        Just(search_input::Event::Clear),
        Just(search_input::Event::Submit),
        any::<bool>().prop_map(search_input::Event::SetSearching),
        Just(search_input::Event::DebounceExpired),
