        Just(number_input::Event::StartScrub),
        (-10.0_f64..10.0).prop_map(number_input::Event::Scrub),
        Just(number_input::Event::EndScrub),
        (-5.0_f64..5.0).prop_map(|delta| number_input::Event::Wheel { delta }),
