    )
        .prop_map(
            |(disabled, invalid, otp, mask, required, auto_submit, mode)| pin_input::Props {
                id: "pin-input".to_string(),
                value: None,
                default_value: Vec::new(),
                length: 4,
                disabled,
                invalid,
                otp,
                mask,
                placeholder: Some("_".to_string()),
                mode,
                name: Some("pin".to_string()),
