pub enum Key {
    /// String key — the universal fallback.
    String(String),

    /// Integer key — allocation-free for numeric identifiers.
    Int(u64),

    /// UUID key — allocation-free for UUID-based identifiers.
    ///
    /// Available only when the `uuid` feature is enabled. Provides a
    /// 16-byte `Copy` key without heap allocation, compared to the 36-byte
    /// `String` representation of a UUID.
    #[cfg(feature = "uuid")]
    Uuid(uuid::Uuid),
}

/// Manual `PartialOrd` / `Ord` implementation: `Int` keys sort before `String`
/// keys so that numeric identifiers (common in database-driven collections)
/// cluster together at the front of `BTreeSet<Key>` used by `selection::State`.
/// Within each variant the natural ordering applies (`u64::cmp` for `Int`,
/// lexicographic for `String`).
///
/// When the `uuid` feature is enabled, the ordering is `Int < Uuid < String`:
/// numeric IDs first, then UUIDs (also structured identifiers), then
/// arbitrary strings.
///
/// **Note on mixed-key ordering**: When a collection contains
/// both `Key::Int` and `Key::String` keys, all `Int` keys sort before all
/// `String` keys. This is intentional for database-backed collections where
/// numeric IDs and string IDs are not intermixed. If your use case requires a
/// single unified ordering, normalize all keys to `Key::String` (e.g., via
/// `Key::str(id.to_string())`). For database-sourced numeric IDs, prefer
/// `Key::from_database_id(u64)` (alias for `Key::Int`) to make the sort
/// behavior explicit.
impl PartialOrd for Key {
    fn partial_cmp(&self, other: &Self) -> Option<core::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for Key {
    fn cmp(&self, other: &Self) -> core::cmp::Ordering {
        // Variant ordering: Int (0) < Uuid (1) < String (2).
        // Within the same variant: natural ordering.
        match (self, other) {
            (Key::Int(a), Key::Int(b)) => a.cmp(b),
            (Key::String(a), Key::String(b)) => a.cmp(b),
            (Key::Int(_), Key::String(_)) => core::cmp::Ordering::Less,
            (Key::String(_), Key::Int(_)) => core::cmp::Ordering::Greater,
            #[cfg(feature = "uuid")]
            (Key::Uuid(a), Key::Uuid(b)) => a.cmp(b),
            #[cfg(feature = "uuid")]
            (Key::Int(_), Key::Uuid(_)) => core::cmp::Ordering::Less,
            #[cfg(feature = "uuid")]
            (Key::Uuid(_), Key::Int(_)) => core::cmp::Ordering::Greater,
            #[cfg(feature = "uuid")]
            (Key::Uuid(_), Key::String(_)) => core::cmp::Ordering::Less,
            #[cfg(feature = "uuid")]
            (Key::String(_), Key::Uuid(_)) => core::cmp::Ordering::Greater,
        }
    }
}

impl Key {
    /// Construct a string key.
    #[must_use]
    pub fn str(s: impl Into<String>) -> Self {
        Key::String(s.into())
    }

//! RadioGroup component state machine and connect API.
//!
//! This module implements the framework-agnostic `RadioGroup` machine defined
//! in `spec/components/input/radio-group.md`. The machine owns single-value
//! selection, stable-key roving focus, per-item disabled state, and ARIA/form
//! metadata while leaving DOM focus resolution to framework adapters.

use alloc::{
    string::{String, ToString as _},
    vec::Vec,
};
use core::fmt::{self, Debug};

use ars_collections::Key;
use ars_core::{
    AriaAttr, AttrMap, Bindable, Callback, ComponentIds, ComponentMessages, ComponentPart,
    ConnectApi, Direction, Env, HtmlAttr, KeyboardKey, Orientation, PendingEffect, TransitionPlan,
    no_cleanup,
};
use ars_interactions::KeyboardEventData;

/// The state of the `RadioGroup` component.
#[derive(Clone, Debug, Default, PartialEq, Eq)]
pub enum State {
    /// No item is currently focused inside the group.
    #[default]
    Idle,

    /// A radio item has focus.
    Focused {
        /// The stable value key of the focused item.
        item: Key,
    },
}

/// Events accepted by the `RadioGroup` component.
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum Event {
    /// Select a radio item by value.
    SelectValue(Key),

    /// Focus moved to a specific item.
    FocusItem {
        /// The stable value key of the focused item.
        item: Key,

        /// Whether focus was initiated by keyboard navigation.
        is_keyboard: bool,
    },

    /// Focus left the group.
    Blur,

    /// Move focus to the next enabled item.
    FocusNext,

    /// Move focus to the previous enabled item.
    FocusPrev,

    /// Move focus to the first enabled item.
    FocusFirst,

    /// Move focus to the last enabled item.
    FocusLast,

    /// Register or update a rendered item.
    RegisterItem(Radio),

    /// Replace the rendered item registry with the current logical order.
    SetItems(Vec<Radio>),

    /// Unregister a rendered item by value.
    UnregisterItem(Key),

    /// Restore the selected value to [`Props::default_value`].
    Reset,

    /// Synchronize the externally controlled value prop.
    SetValue(Option<Key>),

    /// Synchronize output-affecting props stored in context.
    SetProps,

    /// Track whether a description part is rendered.
    SetHasDescription(bool),

    /// Track whether an error message part is rendered.
    SetHasErrorMessage(bool),
}

/// Context for the `RadioGroup` component.
#[derive(Clone, Debug, PartialEq)]
pub struct Context {
    /// Selected radio value, controlled or uncontrolled.
    pub value: Bindable<Option<Key>>,

    /// The stable value key of the focused item.
    pub focused_item: Option<Key>,

    /// True when focus was initiated by keyboard navigation.
    pub focus_visible: bool,

    /// Whether the whole group is disabled.
    pub disabled: bool,

    /// Whether the selected value is read-only.
    pub readonly: bool,

    /// Whether selecting a value is required.
    pub required: bool,

    /// Whether the field is in an invalid state.
    pub invalid: bool,

    /// Layout axis used for arrow-key navigation and ARIA.
    pub orientation: Orientation,

    /// Text direction for RTL-aware horizontal arrow-key navigation.
    pub dir: Direction,

    /// Shared native form field name for all radio inputs.
    pub name: Option<String>,

    /// Whether arrow-key focus wraps at the ends.
    pub loop_focus: bool,

    /// Whether a description part is rendered and should be referenced.
    pub has_description: bool,

    /// Whether an error message part is rendered and should be referenced.
    pub has_error_message: bool,

    /// Ordered radio item registry used for roving focus.
    pub items: Vec<Radio>,

    /// Stable IDs for radio-group anatomy parts.
    pub ids: ComponentIds,
}

/// A registered radio item.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct Radio {
    /// Stable submitted value and identity key for this radio item.
    pub value: Key,

    /// Whether this item is disabled independent of the group state.
    pub disabled: bool,
}

impl Radio {
    /// Creates an enabled radio item with the given stable value key.
    #[must_use]
    pub fn new(value: impl Into<Key>) -> Self {
        Self {
            value: value.into(),
            disabled: false,
        }
    }

    /// Marks this radio item as disabled or enabled.
    #[must_use]
    pub const fn disabled(mut self, disabled: bool) -> Self {
        self.disabled = disabled;
        self
    }
}

/// Props for the `RadioGroup` component.
#[derive(Clone, Debug, PartialEq, ars_core::HasId)]
pub struct Props {
    /// Component instance ID.
    pub id: String,

    /// Controlled selected value. When `Some`, the component is controlled.
    pub value: Option<Key>,

    /// Default selected value for uncontrolled mode.
    pub default_value: Option<Key>,

    /// Whether the whole group is disabled.
    pub disabled: bool,

    /// Whether the selected value is read-only.
    pub readonly: bool,

    /// Whether selecting a value is required.
    pub required: bool,

    /// Whether the field is in an invalid state.
    pub invalid: bool,

    /// Layout axis used for arrow-key navigation and ARIA.
    pub orientation: Orientation,

    /// Text direction for RTL-aware horizontal arrow-key navigation.
    pub dir: Direction,

    /// Shared native form field name for all radio inputs.
    pub name: Option<String>,

    /// ID of the associated native form element.
    pub form: Option<String>,

    /// Whether arrow-key focus wraps at the ends.
    pub loop_focus: bool,

    /// Called when user intent requests a new selected value.
    pub on_value_change: Option<Callback<dyn Fn(Option<Key>) + Send + Sync>>,
}

impl Default for Props {
    fn default() -> Self {
        Self {
            id: String::new(),
            value: None,
            default_value: None,
            disabled: false,
            readonly: false,
            required: false,
            invalid: false,
            orientation: Orientation::Vertical,
            dir: Direction::Ltr,
            name: None,
            form: None,
            loop_focus: true,
            on_value_change: None,
