                        selected == item_value
                    } else {
                        first_enabled(self.ctx).as_ref() == Some(item_value)
                    };
                }

                first_enabled(self.ctx).as_ref() == Some(item_value)
            }
        }
    }
}

#[derive(Clone, Copy)]
enum FocusStep {
    Next,
    Prev,
}

fn reset_value_plan(ctx: &Context, next: Option<Key>) -> TransitionPlan<Machine> {
    value_change_plan(ctx, next)
}

