cd /Users/ericson/Workspace/Rust/ars-ui.worktrees/audit-input-components; prev=""; while true; do
  reactions=$(gh api repos/fogodev/ars-ui/issues/692/reactions --jq '.[] | "\(.user.login):\(.content)"' 2>/dev/null | sort);
  threads=$(gh api graphql -f query='query($o:String!,$r:String!,$n:Int!){repository(owner:$o,name:$r){pullRequest(number:$n){reviewThreads(first:100){nodes{id isResolved comments(first:1){nodes{author{login}}}}}}}}' -F o=fogodev -F r=ars-ui -F n=692 --jq '.data.repository.pullRequest.reviewThreads.nodes | map(select(.isResolved==false and (.comments.nodes[0].author.login | test("codex"; "i")))) | length' 2>/dev/null);
  codex_eyes=$(echo "$reactions" | grep -E "codex.*:eyes$" || true);
  codex_thumb=$(echo "$reactions" | grep -E "codex.*:\+1$" || true);
  cur="reactions=[$reactions] threads=$threads";
  [ "$cur" != "$prev" ] && echo "[change] $cur";
  prev=$cur;
  if [ -n "$codex_thumb" ]; then echo "VERDICT=approval"; exit 0; fi;
  if [ -z "$codex_eyes" ] && [ "$threads" -gt 0 ]; then echo "VERDICT=needs_action threads=$threads"; exit 0; fi;
  sleep 120;
done
